INSERT INTO `evaluation_criterion_star_descriptions` VALUES (1527,'CRIT-001',1,'Needs significant support in living, with frequent gaps that require close coaching.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1528,'CRIT-001',2,'Shows early progress in living, but performance is still inconsistent and needs regular follow-up.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1529,'CRIT-001',3,'Meets the expected baseline in living with steady but still improvable habits.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1530,'CRIT-001',4,'Performs well in living and demonstrates reliable, above-average behavior in most situations.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1531,'CRIT-001',5,'Consistently excels in living and models outstanding behavior with minimal guidance.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1532,'CRIT-002',1,'Needs significant support in job and study habits, with major gaps in consistency and commitment.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1533,'CRIT-002',2,'Shows early progress in job and study habits, but still needs regular guidance to stay on track.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1534,'CRIT-002',3,'Meets the baseline expectations in job and study with acceptable consistency.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1535,'CRIT-002',4,'Performs well in job and study and demonstrates reliable learning discipline.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1536,'CRIT-002',5,'Consistently excels in job and study with strong ownership, discipline, and continuous improvement.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1537,'CRIT-003',1,'Needs significant support in relationships and teamwork, with frequent conflict or withdrawal.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1538,'CRIT-003',2,'Shows some positive interactions but still struggles to build stable support and collaboration.','2026-03-17 06:40:21','2026-03-17 06:40:21'),(1539,'CRIT-003',3,'Maintains acceptable relationships and parti